│   │       └── doc-writer.js
│   │
│   ├── knowledge/
│   │   └── retrieval.js               # 知识检索（标签 + 关键词匹配）
│   │
│   ├── tools/
│   │   └── index.js                   # 工具注册 + 路由执行
│   │
│   ├── prompt/
│   │   ├── augmentation.js            # 构建增强 prompt（拼接记忆、Skill、知识、工具定义）
│   │   └── templates.js               # 系统提示词 + 工具调用格式说明
│   │
│   └── utils/
│       ├── xml-parser.js              # XML 工具调用解析 + 剥离
│       └── dom-utils.js               # DOM 辅助函数
│
├── skills/                            # 内置 Skill 完整定义（可选，从 core/skill/builtins 复制）
│   ├── code-review/
│   │   └── SKILL.md
│   └── translate/
│       └── SKILL.md
│
└── docs/
    └── 精简版设计文档.md               # 本设计文档
```

### 3.3 文件数量预估

| 目录 | 文件数 |
|---|---|
| manifest.json + icons | 4 |
| background/ | 1 |
| content/ | 2 |
| sidepanel/ | ~10 |
| core/ | ~18 |
| skills/ | ~3 |
| docs/ | 1 |
| **总计** | **~39** |

### 3.4 核心流程

```
用户输入（DeepSeek 网页）
  ↓
main world: monkey-patch fetch，拦截 /chat/completions 请求
  ↓
读取 IndexedDB（相关记忆、Skill、知识）
  ↓
增强 prompt（注入工具定义 + 记忆上下文 + 知识片段）
  ↓
发送到 DeepSeek API
  ↓
AI 回复（含 <tool_call>XML</tool_call>）
  ↓
isolated world: 解析响应中的 XML 工具调用
  ↓
发送到 Service Worker 执行工具
  ↓
将工具执行结果注入 DOM（渲染在回复下方）
  ↓
[可选] 自动续跑：将工具结果发回 AI，获取最终回复
```

### 3.5 存储设计

全部使用原生 IndexedDB，一个数据库 `deepseek-enhanced`：

| Object Store | keyPath | 索引 |
|---|---|---|
| `memories` | id (自增) | type, tags, pinned, updatedAt |
| `skills` | id | name |
| `knowledge_items` | id (自增) | category, tags, updatedAt |
| `knowledge_categories` | id | name |

```javascript
// IndexedDB schema
const DB_NAME = 'deepseek-enhanced';
const DB_VERSION = 1;

const STORES = {
  memories:    { keyPath: 'id', autoIncrement: true, indexes: ['type', 'tags', 'pinned', 'updatedAt'] },
  skills:      { keyPath: 'id', indexes: ['name'] },
  knowledge_items: { keyPath: 'id', autoIncrement: true, indexes: ['category', 'tags', 'updatedAt'] },
  knowledge_categories: { keyPath: 'id', indexes: ['name'] },
};
```

chrome.storage.local 只存：

```
{
  token: 'sk-xxx',             // 用户 API Key
  autoSaveMemory: true,        // 自动保存记忆
  language: 'zh_CN',           // 界面语言
}
```

---

## 四、核心实现细节

### 4.1 fetch 拦截（main world）

```javascript
// content/fetch-interceptor.js
// 通过 <script> 注入到页面主世界，拦截所有 fetch 请求

const originalFetch = window.fetch;

window.fetch = async function(url, options = {}) {
  const urlStr = typeof url === 'string' ? url : url.href;
  const bodyStr = typeof options.body === 'string' ? options.body : '';

  if (urlStr.includes('/chat/completions') && bodyStr) {
    try {
      const body = JSON.parse(bodyStr);
      const enhancedBody = await augmentRequest(body);
      options.body = JSON.stringify(enhancedBody);
    } catch (e) {
      console.error('[DeepSeek Enhanced] fetch augment error:', e);
    }
  }

  const response = await originalFetch.call(this, url, options);

  // 拦截响应，解析工具调用
  if (urlStr.includes('/chat/completions')) {
    const clonedResponse = response.clone();
    interceptResponse(clonedResponse).catch(console.error);
  }

  return response;
};
```

### 4.2 prompt 增强

```javascript
// core/prompt/augmentation.js

async function augmentRequest(body) {
  const messages = body.messages;
  const lastUserMsg = getLastUserMessage(messages);
  if (!lastUserMsg) return body;

  // 1. 匹配相关记忆
  const memories = await matchMemories(lastUserMsg.content);

  // 2. 匹配 Skill（检测 /xxx 前缀）
  const skillContext = await matchSkill(lastUserMsg.content);

  // 3. 搜索知识库
  const knowledgeContext = await searchKnowledge(lastUserMsg.content);

  // 4. 注入工具定义
  const toolDefinitions = getToolDefinitions();

  // 5. 构建增强的 system prompt
  const enhancedSystemMsg = buildSystemPrompt({
    memories,
    skillContext,
    knowledgeContext,
    toolDefinitions,
  });

  // 6. 注入到 messages 数组
  const systemIdx = messages.findIndex(m => m.role === 'system');
  if (systemIdx >= 0) {
    messages[systemIdx].content = enhancedSystemMsg;
  } else {
    messages.unshift({ role: 'system', content: enhancedSystemMsg });
  }

  return { ...body, messages };
}
```

### 4.3 工具调用解析

```javascript
// core/utils/xml-parser.js

// AI 回复中包含以下格式的 XML：
// <tool_call>memory_save{"type":"user","name":"职业","content":"用户是前端开发者"}</tool_call>

const TOOL_CALL_REGEX = /<tool_call>(\w+)(\{.*?\})<\/tool_call>/g;

function parseToolCalls(text) {
  const calls = [];
  let match;
  while ((match = TOOL_CALL_REGEX.exec(text)) !== null) {
    try {
      calls.push({
        tool: match[1],
        params: JSON.parse(match[2]),
      });
    } catch (e) {
      console.warn('Tool call parse error:', e);
    }
  }
  return calls;
}

function stripToolCalls(text) {
  return text.replace(TOOL_CALL_REGEX, '').trim();
}
```

### 4.4 工具运行时

```javascript
// core/tools/index.js

import { MemoryStore } from '../db/memory-store.js';
import { KnowledgeStore } from '../db/knowledge-store.js';
import { searchWeb } from './web-search.js';
import { fetchWeb } from './web-fetch.js';

const TOOLS = {
  async memory_save(params) {
    return await MemoryStore.save(params);
  },
  async memory_update(params) {
    return await MemoryStore.update(params.id, params);
  },
  async memory_delete(params) {
    return await MemoryStore.delete(params.id);
  },
  async knowledge_save(params) {
    return await KnowledgeStore.save(params);
  },
  async knowledge_search(params) {
    return await KnowledgeStore.search(params.query, params.limit || 5);
  },
  async web_search(params) {
    return await searchWeb(params.query);
  },
  async web_fetch(params) {
    return await fetchWeb(params.url);
  },
};

export async function executeTool(toolName, params) {
  const fn = TOOLS[toolName];
  if (!fn) throw new Error(`Unknown tool: ${toolName}`);
  return await fn(params);
}
```

