// Background Service Worker
// 职责：消息路由 + 工具执行 + prompt 增强

import { executeTool } from '../core/tools/index.js';
import { MemoryStore } from '../core/db/memory-store.js';
import { SkillStore } from '../core/db/skill-store.js';
import { KnowledgeStore } from '../core/db/knowledge-store.js';
import { augmentRequest } from '../core/prompt/augmentation.js';

// ==================== 消息处理 ====================

chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
  handleMessage(message, sender).then(sendResponse).catch(err => {
    console.error('[DeepSeek Enhanced] SW error:', err);
    sendResponse({ error: err.message });
  });
  return true; // 保持消息通道开放（异步响应）
});

async function handleMessage(message, sender) {
  switch (message.type) {
    // --- Prompt 增强（来自 fetch-interceptor） ---
    case 'augmentRequest':
      return await augmentRequest(message.body);

    // --- 工具执行 ---
    case 'executeTool':
      return await executeTool(message.tool, message.params);

    // --- 记忆 CRUD ---
    case 'getMemories':
      return await MemoryStore.getAll();
    case 'saveMemory':
      return await MemoryStore.save(message.memory);
    case 'updateMemory':
      return await MemoryStore.update(message.id, message.memory);
    case 'deleteMemory':
      return await MemoryStore.delete(message.id);

    // --- Skill CRUD ---
    case 'getSkills':
      return await SkillStore.getAll();
    case 'saveSkill':
      return await SkillStore.save(message.skill);
    case 'deleteSkill':
      return await SkillStore.delete(message.id);

    // --- 知识库 CRUD ---
    case 'getKnowledgeItems':
      return await KnowledgeStore.allItems();
    case 'saveKnowledgeItem':
      return await KnowledgeStore.saveItem(message.item);
    case 'updateKnowledgeItem':
      return await KnowledgeStore.updateItem(message.id, message.item);
    case 'deleteKnowledgeItem':
      return await KnowledgeStore.deleteItem(message.id);
    case 'getKnowledgeCategories':
      return await KnowledgeStore.allCategories();
    case 'saveKnowledgeCategory':
      return await KnowledgeStore.saveCategory(message.category);
    case 'deleteKnowledgeCategory':
      return await KnowledgeStore.deleteCategory(message.id);

    // --- 搜索 ---
    case 'searchKnowledge':
      return await KnowledgeStore.searchItems(message.query, message.limit || 5);

    // --- 设置 ---
    case 'getSettings':
      return await chrome.storage.local.get(message.keys || null);
    case 'saveSettings':
      await chrome.storage.local.set(message.settings);
      return { success: true };

    default:
      throw new Error(`Unknown message type: ${message.type}`);
  }
}

// ==================== 点击图标打开侧边栏 ====================

chrome.action.onClicked.addListener((tab) => {
  chrome.sidePanel.open({ windowId: tab.windowId });
});

console.log('[DeepSeek Enhanced] Service Worker ready');

/**
 * fetch-interceptor.js
 * 注入到页面主世界，拦截 DeepSeek 网页的 fetch 请求
 * 对 /chat/completions 请求进行 prompt 增强
 * 对响应进行工具调用解析
 */

(async function () {
  if (window.__deepseekEnhancedInjected) return;
  window.__deepseekEnhancedInjected = true;

  const originalFetch = window.fetch;

  window.fetch = async function (url, options = {}) {
    const urlStr = typeof url === 'string' ? url : (url.href || url.url || '');
    const bodyStr = typeof options.body === 'string' ? options.body : '';

    // ========== 拦截请求：增强 prompt ==========
    let enhanced = false;
    if (urlStr.includes('/chat/completions') && bodyStr) {
      try {
        const body = JSON.parse(bodyStr);
        if (body.messages) {
          const enhancedBody = await augmentViaSW(body);
          options.body = JSON.stringify(enhancedBody);
          enhanced = true;
        }
      } catch (e) {
        console.warn('[DeepSeek Enhanced] intercept error:', e);
      }
    }

    // ========== 发送请求 ==========
    const response = await originalFetch.call(this, url, options);

    // ========== 拦截响应：解析工具调用 ==========
    if (urlStr.includes('/chat/completions') && enhanced) {
      try {
        const cloned = response.clone();
        processResponse(cloned).catch(e =>
          console.warn('[DeepSeek Enhanced] response process error:', e)
        );
      } catch (e) {
        // clone 失败则忽略
      }
    }

    return response;
  };

  /**
   * 通过 Service Worker 进行 prompt 增强
   */
  async function augmentViaSW(body) {
    return new Promise((resolve) => {
      chrome.runtime.sendMessage(
        { type: 'augmentRequest', body },
        (response) => {
          if (chrome.runtime.lastError || !response) {
            resolve(body);
          } else {
            resolve(response);
          }
        }
      );
    });
  }

  /**
   * 处理响应：解析工具调用并通知 UI 层
   */
  async function processResponse(response) {
    const data = await response.json();
    const choices = data.choices || [];
    for (const choice of choices) {
      const content = choice.message?.content || '';
      if (!content) continue;

      // 通知 UI 层处理工具调用
      window.postMessage(
        {
          type: '__DEEPSEEK_ENHANCED_RESPONSE__',
          content,
          choiceIndex: choice.index,
        },
        '*'
      );
    }
  }

  console.log('[DeepSeek Enhanced] Fetch interceptor injected');
})();

/**
 * ui-injector.js (isolated world content script)
 * 职责：
 *   1. 将 fetch-interceptor.js 注入到页面主世界
 *   2. 监听来自主世界的工具调用消息
 *   3. 渲染工具执行结果到 DeepSeek 页面
 *   4. 可选：自动续跑（将工具结果发回 AI）
 */

// ==================== 注入主世界脚本 ====================

(function injectInterceptor() {
  const script = document.createElement('script');
  script.src = chrome.runtime.getURL('content/fetch-interceptor.js');
  script.onload = () => {
    script.remove();
    console.log('[DeepSeek Enhanced] Interceptor injected into main world');
  };
  (document.head || document.documentElement).appendChild(script);
})();

// ==================== 监听主世界消息 ====================

window.addEventListener('message', async (event) => {
  if (event.source !== window) return;
  if (!event.data || event.data.type !== '__DEEPSEEK_ENHANCED_RESPONSE__') return;

  const { content } = event.data;
  await processResponse(content);
});

// ==================== 工具执行 + 渲染 ====================

let toolBlockContainer = null;

async function processResponse(aiContent) {
  const toolCalls = parseToolCallsLocally(aiContent);
  if (toolCalls.length === 0) return;

  // 显示工具执行块
  const block = getOrCreateToolBlock();
  const statusEl = block.querySelector('.deepseek-enhanced-status');
  const detailEl = block.querySelector('.deepseek-enhanced-detail');

  block.style.display = 'block';
  statusEl.textContent = `🔧 正在执行 ${toolCalls.length} 个工具...`;
  detailEl.innerHTML = '';

  // 逐个执行工具
  const results = [];
  for (const call of toolCalls) {
    try {
      const result = await sendToSW({
        type: 'executeTool',
        tool: call.tool,
        params: call.params,
      });
      results.push({ call, result });
      detailEl.innerHTML += renderToolResult(call, result);
    } catch (e) {
      results.push({ call, result: { error: e.message } });
      detailEl.innerHTML += renderToolResult(call, { error: e.message });
    }
  }

  const successCount = results.filter(r => r.result && !r.result.error).length;
  statusEl.textContent = `🔧 已执行 ${successCount}/${toolCalls.length} 个工具`;

  // 清除隐藏状态
  block.classList.add('done');
}

/**
 * 本地解析工具调用（避免跨上下文导入模块）
 */
function parseToolCallsLocally(text) {
  const regex = /<tool_call>(\w+)(\{[\s\S]*?\})?<\/tool_call>/g;
  const calls = [];
  let match;
  while ((match = regex.exec(text)) !== null) {
    let params = {};
    if (match[2]) {
      try { params = JSON.parse(match[2]); } catch (e) {}
    }
    calls.push({ tool: match[1], params });
  }
  return calls;
}

/**
 * 创建或获取工具执行块容器
 */
function getOrCreateToolBlock() {
  if (toolBlockContainer && document.body.contains(toolBlockContainer)) {
    return toolBlockContainer;
  }

  const container = document.createElement('div');
  container.className = 'deepseek-enhanced-tool-block';
  container.style.cssText = `
    position: fixed;
    bottom: 80px;
    right: 20px;
    width: 360px;
    max-height: 300px;
    overflow-y: auto;
    background: #ffffff;
    border: 1px solid #e2e8f0;
    border-radius: 12px;
    box-shadow: 0 4px 24px rgba(0,0,0,0.12);
    padding: 16px;
    z-index: 99999;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    font-size: 13px;
    display: none;
  `;
  container.innerHTML = `
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;">
      <span class="deepseek-enhanced-status" style="font-weight:600;color:#1e293b;"></span>
      <div>
        <button class="deepseek-enhanced-expand" style="background:none;border:none;cursor:pointer;color:#64748b;font-size:14px;padding:2px 6px;" title="展开/折叠">▼</button>
        <button class="deepseek-enhanced-close" style="background:none;border:none;cursor:pointer;color:#64748b;font-size:16px;padding:2px 6px;" title="关闭">×</button>
      </div>
    </div>
    <div class="deepseek-enhanced-detail" style="border-top:1px solid #f1f5f9;padding-top:8px;"></div>
  `;

  // 事件绑定
  container.querySelector('.deepseek-enhanced-close').addEventListener('click', () => {
    container.style.display = 'none';
  });

  const expandBtn = container.querySelector('.deepseek-enhanced-expand');
  const detailEl = container.querySelector('.deepseek-enhanced-detail');
  expandBtn.addEventListener('click', () => {
    const hidden = detailEl.style.display === 'none';
    detailEl.style.display = hidden ? 'block' : 'none';
    expandBtn.textContent = hidden ? '▼' : '▶';
  });

  document.body.appendChild(container);
  toolBlockContainer = container;
  return container;
}

/**
 * 渲染单个工具结果
 */
function renderToolResult(call, result) {
  const success = result && !result.error;
  return `
    <div style="margin-bottom:8px;padding:8px;background:${success ? '#f0fdf4' : '#fef2f2'};border-radius:6px;border-left:3px solid ${success ? '#22c55e' : '#ef4444'};">
      <div style="font-weight:600;margin-bottom:4px;color:${success ? '#166534' : '#991b1b'};">
        ${success ? '✅' : '❌'} ${call.tool}
      </div>
      <div style="color:#475569;font-size:12px;word-break:break-all;">
        ${escapeHtml(JSON.stringify(result, null, 0).substring(0, 200))}
      </div>
    </div>
  `;
}

function escapeHtml(str) {
  const div = document.createElement('div');
  div.textContent = str;
  return div.innerHTML;
}

/**
 * 向 Service Worker 发送消息
 */
function sendToSW(message) {
  return new Promise((resolve, reject) => {
    chrome.runtime.sendMessage(message, (response) => {
      if (chrome.runtime.lastError) {
        reject(new Error(chrome.runtime.lastError.message));
      } else {
        resolve(response);
      }
    });
  });
}

console.log('[DeepSeek Enhanced] UI Injector ready');

/**
 * sidepanel/app.js
 * 侧边栏主入口：Tab 导航 + 页面加载 + 设置面板
 */

import MemoriesPage from './pages/memories.js';
import SkillsPage from './pages/skills.js';
import KnowledgePage from './pages/knowledge.js';
import SettingsPanel from './pages/settings.js';

// ==================== 状态 ====================

const state = {
  currentTab: 'memories',
  pages: {},
};

// ==================== 初始化 ====================

document.addEventListener('DOMContentLoaded', () => {
  initTabs();
  initSettingsBtn();
  loadPage('memories');
});

// ==================== Tab 导航 ====================

function initTabs() {
  const tabs = document.querySelectorAll('.tab');
  tabs.forEach(tab => {
    tab.addEventListener('click', () => {
      const tabName = tab.dataset.tab;
      if (state.currentTab === tabName) return;

      // 更新活动状态
      tabs.forEach(t => t.classList.remove('active'));
      tab.classList.add('active');

      state.currentTab = tabName;
      loadPage(tabName);
    });
  });
}

// ==================== 页面加载 ====================

async function loadPage(tabName) {
  const container = document.getElementById('pageContainer');
  const settingsPanel = document.getElementById('settingsPanel');

  // 隐藏设置面板
  settingsPanel.style.display = 'none';

  // 缓存页面实例
  if (!state.pages[tabName]) {
    state.pages[tabName] = createPage(tabName);
  }

  const page = state.pages[tabName];
  container.innerHTML = '';
  container.appendChild(page.container);

  // 触发页面的初始化/刷新
  if (page.refresh) {
    await page.refresh();
  }
}

function createPage(tabName) {
  switch (tabName) {
    case 'memories':
      return MemoriesPage();
    case 'skills':
      return SkillsPage();
    case 'knowledge':
      return KnowledgePage();
    default:
      return { container: document.createElement('div') };
  }
}

// ==================== 设置按钮 ====================

function initSettingsBtn() {
  const btn = document.getElementById('settingsBtn');
  btn.addEventListener('click', () => {
    const container = document.getElementById('pageContainer');
    const settingsPanel = document.getElementById('settingsPanel');

    if (settingsPanel.style.display === 'none') {
      // 显示设置
      container.innerHTML = '';
      settingsPanel.style.display = 'block';
      SettingsPanel.render(settingsPanel);
    } else {
      // 隐藏设置，回到当前 Tab
      settingsPanel.style.display = 'none';
      loadPage(state.currentTab);
    }
  });
}

// ==================== SW 通信工具 ====================

/**
 * 向 Service Worker 发送消息
 */
export function sendToSW(message) {
  return new Promise((resolve, reject) => {
    chrome.runtime.sendMessage(message, (response) => {
      if (chrome.runtime.lastError) {
        reject(new Error(chrome.runtime.lastError.message));
      } else if (response && response.error && typeof response.error === 'string') {
        reject(new Error(response.error));
      } else {
        resolve(response);
      }
    });
  });
}

/**
 * 格式化日期
 */
export function formatDate(ts) {
  if (!ts) return '';
  const d = new Date(ts);
  const month = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  const hours = String(d.getHours()).padStart(2, '0');
  const min = String(d.getMinutes()).padStart(2, '0');
  return `${month}-${day} ${hours}:${min}`;
}

/**
 * HTML 转义
 */
export function escapeHtml(str) {
  const div = document.createElement('div');
  div.textContent = str;
  return div.innerHTML;
}

/**
 * 创建 DOM 元素
 */
export function createEl(tag, attrs = {}, children = []) {
  const el = document.createElement(tag);
  for (const [key, val] of Object.entries(attrs)) {
    if (key === 'className') {
      el.className = val;
    } else if (key === 'textContent') {
      el.textContent = val;
    } else if (key === 'innerHTML') {
      el.innerHTML = val;
    } else if (key.startsWith('on')) {
      el.addEventListener(key.slice(2).toLowerCase(), val);
    } else if (key === 'style' && typeof val === 'object') {
      Object.assign(el.style, val);
    } else {
      el.setAttribute(key, val);
    }
  }
  for (const child of children) {
    if (typeof child === 'string') {
      el.appendChild(document.createTextNode(child));
    } else if (child instanceof Node) {
      el.appendChild(child);
    }
  }
  return el;
}

/**
 * IndexedDB 封装 - 提供 Promise 化的 CRUD 操作
 */

import { DB_NAME, DB_VERSION, STORE_NAMES } from '../constants.js';

let db = null;

/**
 * 打开数据库，如果不存在则创建
 */
export async function openDB() {
  if (db) return db;
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onerror = () => reject(request.error);
    request.onsuccess = () => {
      db = request.result;
      resolve(db);
    };

    request.onupgradeneeded = (event) => {
      const database = event.target.result;

      // 记忆表
      if (!database.objectStoreNames.contains(STORE_NAMES.MEMORIES)) {
        const store = database.createObjectStore(STORE_NAMES.MEMORIES, {
          keyPath: 'id',
          autoIncrement: true,
        });
        store.createIndex('type', 'type', { unique: false });
        store.createIndex('pinned', 'pinned', { unique: false });
        store.createIndex('updatedAt', 'updatedAt', { unique: false });
      }

      // 自定义 Skill 表
      if (!database.objectStoreNames.contains(STORE_NAMES.SKILLS)) {
        const store = database.createObjectStore(STORE_NAMES.SKILLS, {
          keyPath: 'id',
        });
        store.createIndex('name', 'name', { unique: true });
      }

      // 知识库条目表
      if (!database.objectStoreNames.contains(STORE_NAMES.KNOWLEDGE_ITEMS)) {
        const store = database.createObjectStore(STORE_NAMES.KNOWLEDGE_ITEMS, {
          keyPath: 'id',
          autoIncrement: true,
        });
        store.createIndex('category', 'category', { unique: false });
        store.createIndex('updatedAt', 'updatedAt', { unique: false });
      }

      // 知识库分类表
      if (!database.objectStoreNames.contains(STORE_NAMES.KNOWLEDGE_CATEGORIES)) {
        database.createObjectStore(STORE_NAMES.KNOWLEDGE_CATEGORIES, {
          keyPath: 'id',
        });
      }
    };
  });
}

function getStore(storeName, mode = 'readonly') {
  return db.transaction(storeName, mode).objectStore(storeName);
}

// ---- 通用 CRUD ----

export async function getAll(storeName) {
  await openDB();
  return new Promise((resolve, reject) => {
    const request = getStore(storeName).getAll();
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
}

export async function getById(storeName, id) {
  await openDB();
  return new Promise((resolve, reject) => {
    const request = getStore(storeName).get(id);
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
}

export async function put(storeName, item) {
  await openDB();
  return new Promise((resolve, reject) => {
    const request = getStore(storeName, 'readwrite').put(item);
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
}

export async function remove(storeName, id) {
  await openDB();
  return new Promise((resolve, reject) => {
    const request = getStore(storeName, 'readwrite').delete(id);
    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
}

export async function getByIndex(storeName, indexName, value) {
  await openDB();
  return new Promise((resolve, reject) => {
    const request = getStore(storeName).index(indexName).getAll(value);
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
}

export async function clear(storeName) {
  await openDB();
  return new Promise((resolve, reject) => {
    const request = getStore(storeName, 'readwrite').clear();
    request.onsuccess = () => resolve();
    request.onerror = () => reject(request.error);
  });
}

