 * 基于标签 + 关键词匹配
 */

import { KnowledgeStore } from '../db/knowledge-store.js';

/**
 * 搜索相关知识库条目
 * @param {string} userInput
 * @param {number} limit
 * @returns {Promise<Array>}
 */
export async function searchKnowledge(userInput, limit = 3) {
  const results = await KnowledgeStore.search(userInput, limit);
  return results;
}

/**
 * 知识库 Store - 知识库条目和分类的 CRUD
 */

import { getAll, getById, put, remove, getByIndex } from './indexeddb.js';
import { STORE_NAMES } from '../constants.js';

const ITEMS = STORE_NAMES.KNOWLEDGE_ITEMS;
const CATEGORIES = STORE_NAMES.KNOWLEDGE_CATEGORIES;

export const KnowledgeStore = {
  // ---- 条目 ----

  async allItems() {
    return await getAll(ITEMS);
  },

  async getItem(id) {
    return await getById(ITEMS, id);
  },

  async getItemsByCategory(categoryId) {
    return await getByIndex(ITEMS, 'category', categoryId);
  },

  async saveItem(item) {
    const now = Date.now();
    const data = {
      title: '',
      content: '',
      category: 'default',
      tags: [],
      source: 'manual',
      ...item,
      createdAt: item.createdAt || now,
      updatedAt: now,
    };
    const id = await put(ITEMS, data);
    return { ...data, id };
  },

  async updateItem(id, updates) {
    const existing = await getById(ITEMS, id);
    if (!existing) throw new Error(`Knowledge item not found: ${id}`);
    const merged = { ...existing, ...updates, id, updatedAt: Date.now() };
    await put(ITEMS, merged);
    return merged;
  },

  async deleteItem(id) {
    return await remove(ITEMS, id);
  },

  /**
   * 搜索知识库：按标题、内容、标签匹配
   */
  async searchItems(query, limit = 5) {
    const all = await getAll(ITEMS);
    const q = query.toLowerCase();
    const results = [];
    for (const item of all) {
      let score = 0;
      if (item.title.toLowerCase().includes(q)) score += 10;
      if (item.content.toLowerCase().includes(q)) score += 1;
      if (item.tags.some(t => t.toLowerCase().includes(q))) score += 5;
      if (score > 0) results.push({ ...item, _score: score });
    }
    results.sort((a, b) => b._score - a._score);
    return results.slice(0, limit);
  },

  // ---- 分类 ----

  async allCategories() {
    return await getAll(CATEGORIES);
  },

  async saveCategory(cat) {
    const item = {
      id: cat.id || `cat_${Date.now()}`,
      name: cat.name || '未分类',
      description: cat.description || '',
      color: cat.color || '#6366f1',
      createdAt: cat.createdAt || Date.now(),
    };
    await put(CATEGORIES, item);
    return item;
  },

  async deleteCategory(id) {
    // 同时删除该分类下的所有条目
    const items = await getByIndex(ITEMS, 'category', id);
    for (const item of items) {
      await remove(ITEMS, item.id);
    }
    return await remove(CATEGORIES, id);
  },
};

// Background Service Worker
// 职责：消息路由 + 工具执行 + prompt 增强

import { executeTool } from '../core/tools/index.js';
import { MemoryStore } from '../core/db/memory-store.js';
import { SkillStore } from '../core/db/skill-store.js';
import { KnowledgeStore } from '../core/db/knowledge-store.js';
import { augmentRequest } from '../core/prompt/augmentation.js';

// ==================== 消息处理 ====================

chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
  handleMessage(message, sender).then(sendResponse).catch(err => {
    console.error('[DeepSeek Enhanced] SW error:', err);
    sendResponse({ error: err.message });
  });
  return true; // 保持消息通道开放（异步响应）
});

async function handleMessage(message, sender) {
  switch (message.type) {
    // --- Prompt 增强（来自 fetch-interceptor） ---
    case 'augmentRequest':
      return await augmentRequest(message.body);

    // --- 工具执行 ---
    case 'executeTool':
      return await executeTool(message.tool, message.params);

    // --- 记忆 CRUD ---
    case 'getMemories':
      return await MemoryStore.getAll();
    case 'saveMemory':
      return await MemoryStore.save(message.memory);
    case 'updateMemory':
      return await MemoryStore.update(message.id, message.memory);
    case 'deleteMemory':
      return await MemoryStore.delete(message.id);

    // --- Skill CRUD ---
    case 'getSkills':
      return await SkillStore.getAll();
    case 'saveSkill':
      return await SkillStore.save(message.skill);
    case 'deleteSkill':
      return await SkillStore.delete(message.id);

    // --- 知识库 CRUD ---
    case 'getKnowledgeItems':
      return await KnowledgeStore.allItems();
    case 'saveKnowledgeItem':
      return await KnowledgeStore.saveItem(message.item);
    case 'updateKnowledgeItem':
      return await KnowledgeStore.updateItem(message.id, message.item);
    case 'deleteKnowledgeItem':
      return await KnowledgeStore.deleteItem(message.id);
    case 'getKnowledgeCategories':
      return await KnowledgeStore.allCategories();
    case 'saveKnowledgeCategory':
      return await KnowledgeStore.saveCategory(message.category);
    case 'deleteKnowledgeCategory':
      return await KnowledgeStore.deleteCategory(message.id);

    // --- 搜索 ---
    case 'searchKnowledge':
      return await KnowledgeStore.searchItems(message.query, message.limit || 5);

    // --- 设置 ---
    case 'getSettings':
      return await chrome.storage.local.get(message.keys || null);
    case 'saveSettings':
      await chrome.storage.local.set(message.settings);
      return { success: true };

    default:
      throw new Error(`Unknown message type: ${message.type}`);
  }
}

// ==================== 点击图标打开侧边栏 ====================

chrome.action.onClicked.addListener((tab) => {
  chrome.sidePanel.open({ windowId: tab.windowId });
});

console.log('[DeepSeek Enhanced] Service Worker ready');

/**
 * Skill Store - 自定义 Skill 的 CRUD
 */

import { getAll, getById, put, remove } from './indexeddb.js';
import { STORE_NAMES } from '../constants.js';

const STORE = STORE_NAMES.SKILLS;

export const SkillStore = {
  async all() {
    return await getAll(STORE);
  },

  async get(id) {
    return await getById(STORE, id);
  },

  async save(skill) {
    const item = {
      id: skill.id || `custom_${Date.now()}`,
      name: skill.name || 'unnamed',
      description: '',
      template: '',
      tags: [],
      source: 'custom',
      createdAt: skill.createdAt || Date.now(),
      updatedAt: Date.now(),
      ...skill,
    };
    await put(STORE, item);
    return item;
  },

  async delete(id) {
    return await remove(STORE, id);
  },
};

/**
 * Skill 注册表
 * 内置 Skill + 自定义 Skill 的统一入口
 */

import { SkillStore } from '../db/skill-store.js';
import { BUILTIN_SKILLS } from './builtins/index.js';

/**
 * 获取 Skill（先查自定义，再查内置）
 * @param {string} name
 * @returns {Object|null}
 */
export function getSkill(name) {
  return BUILTIN_SKILLS[name] || null;
}

/**
 * 获取所有可用 Skill
 * @returns {Promise<Array>}
 */
export async function getAllSkills() {
  const customSkills = await SkillStore.getAll();
  const builtinList = Object.entries(BUILTIN_SKILLS).map(([id, skill]) => ({
    id,
    name: skill.name,
    description: skill.description,
    isBuiltin: true,
  }));
  return [...builtinList, ...customSkills];
}

