      <span class="deepseek-enhanced-status" style="font-weight:600;color:#1e293b;"></span>
      <div>
        <button class="deepseek-enhanced-expand" style="background:none;border:none;cursor:pointer;color:#64748b;font-size:14px;padding:2px 6px;" title="展开/折叠">▼</button>
        <button class="deepseek-enhanced-close" style="background:none;border:none;cursor:pointer;color:#64748b;font-size:16px;padding:2px 6px;" title="关闭">×</button>
      </div>
    </div>
    <div class="deepseek-enhanced-detail" style="border-top:1px solid #f1f5f9;padding-top:8px;"></div>
  `;

  // 事件绑定
  container.querySelector('.deepseek-enhanced-close').addEventListener('click', () => {
    container.style.display = 'none';
  });

  const expandBtn = container.querySelector('.deepseek-enhanced-expand');
  const detailEl = container.querySelector('.deepseek-enhanced-detail');
  expandBtn.addEventListener('click', () => {
    const hidden = detailEl.style.display === 'none';
    detailEl.style.display = hidden ? 'block' : 'none';
    expandBtn.textContent = hidden ? '▼' : '▶';
  });

  document.body.appendChild(container);
  toolBlockContainer = container;
  return container;
}

/**
 * 渲染单个工具结果
 */
function renderToolResult(call, result) {
  const success = result && !result.error;
  return `
    <div style="margin-bottom:8px;padding:8px;background:${success ? '#f0fdf4' : '#fef2f2'};border-radius:6px;border-left:3px solid ${success ? '#22c55e' : '#ef4444'};">
      <div style="font-weight:600;margin-bottom:4px;color:${success ? '#166534' : '#991b1b'};">
        ${success ? '✅' : '❌'} ${call.tool}
      </div>
      <div style="color:#475569;font-size:12px;word-break:break-all;">
        ${escapeHtml(JSON.stringify(result, null, 0).substring(0, 200))}
      </div>
    </div>
  `;
}

function escapeHtml(str) {
  const div = document.createElement('div');
  div.textContent = str;
  return div.innerHTML;
}

/**
 * 向 Service Worker 发送消息
 */
function sendToSW(message) {
  return new Promise((resolve, reject) => {
    chrome.runtime.sendMessage(message, (response) => {
      if (chrome.runtime.lastError) {
        reject(new Error(chrome.runtime.lastError.message));
      } else {
        resolve(response);
      }
    });
  });
}

/**
 * 处理来自主世界的 prompt 增强请求，转发给 SW
 */
async function handleAugmentRequest({ requestId, body }) {
  try {
    const enhancedBody = await sendToSW({ type: 'augmentRequest', body });
    window.postMessage(
      { type: '__DEEPSEEK_AUGMENT_RESULT__', requestId, body: enhancedBody },
      '*'
    );
  } catch (e) {
    // 失败时返回原始 body
    window.postMessage(
      { type: '__DEEPSEEK_AUGMENT_RESULT__', requestId, body },
      '*'
    );
  }
}

console.log('[DeepSeek Enhanced] UI Injector ready');

/**
 * XML 工具调用解析 + 剥离
 *
 * 支持的格式：
 *   <tool_call>tool_name{"key":"value"}</tool_call>
 *   <tool_call>tool_name</tool_call>
 */

const TOOL_CALL_REGEX = /<tool_call>(\w+)(\{[\s\S]*?\})?<\/tool_call>/g;

/**
 * 从文本中解析所有工具调用
 * @param {string} text
 * @returns {Array<{tool: string, params: Object}>}
 */
export function parseToolCalls(text) {
  const calls = [];
  const re = new RegExp(TOOL_CALL_REGEX.source, 'g');
  let match;
  while ((match = re.exec(text)) !== null) {
    const toolName = match[1];
    let params = {};
    if (match[2]) {
      try {
        params = JSON.parse(match[2]);
      } catch (e) {
        console.warn('[DeepSeek Enhanced] JSON parse error for tool:', toolName, e);
        params = { raw: match[2] };
      }
    }
    calls.push({ tool: toolName, params });
  }
  return calls;
}

/**
 * 从文本中移除所有工具调用标签
 * @param {string} text
 * @returns {string}
 */
export function stripToolCalls(text) {
  return text.replace(TOOL_CALL_REGEX, '').trim();
}

/**
 * 检查文本中是否包含工具调用
 * @param {string} text
 * @returns {boolean}
 */
export function hasToolCalls(text) {
  return new RegExp(TOOL_CALL_REGEX.source, 'g').test(text);
}

/**
 * fetch-interceptor.js
 * 注入到页面主世界，拦截 DeepSeek 网页的 fetch 请求
 * 通过 window.postMessage 与 ui-injector（isolated world）通信
 */

(async function () {
  if (window.__deepseekEnhancedInjected) return;
  window.__deepseekEnhancedInjected = true;

  const originalFetch = window.fetch;

  window.fetch = async function (url, options = {}) {
    const urlStr = typeof url === 'string' ? url : (url.href || url.url || '');
    const bodyStr = typeof options.body === 'string' ? options.body : '';

    // ========== 拦截请求：增强 prompt（通过 postMessage 委托给 isolated world）==========
    let enhanced = false;
    if (urlStr.includes('/chat/completions') && bodyStr) {
      try {
        const body = JSON.parse(bodyStr);
        if (body.messages) {
          const enhancedBody = await augmentViaPostMessage(body);
          if (enhancedBody) {
            options.body = JSON.stringify(enhancedBody);
            enhanced = true;
          }
        }
      } catch (e) {
        console.warn('[DeepSeek Enhanced] intercept error:', e);
      }
    }

    // ========== 发送请求 ==========
    const response = await originalFetch.call(this, url, options);

    // ========== 拦截响应：解析工具调用 ==========
    if (urlStr.includes('/chat/completions') && enhanced) {
      try {
        const cloned = response.clone();
        processResponse(cloned).catch(e =>
          console.warn('[DeepSeek Enhanced] response process error:', e)
        );
      } catch (e) {
        // clone 失败则忽略
      }
    }

    return response;
  };

  /**
   * 通过 postMessage 委托 ui-injector（isolated world）调用 SW 进行 prompt 增强
   */
  function augmentViaPostMessage(body) {
    return new Promise((resolve) => {
      const requestId = `augment_${Date.now()}_${Math.random().toString(36).slice(2)}`;

      const handler = (event) => {
        if (event.source !== window) return;
        if (!event.data || event.data.type !== '__DEEPSEEK_AUGMENT_RESULT__') return;
        if (event.data.requestId !== requestId) return;

        window.removeEventListener('message', handler);
        resolve(event.data.body || null);
      };

      window.addEventListener('message', handler);

      window.postMessage(
        { type: '__DEEPSEEK_AUGMENT_REQUEST__', requestId, body },
        '*'
      );

      // 超时兜底
      setTimeout(() => {
        window.removeEventListener('message', handler);
        resolve(null);
      }, 3000);
    });
  }

  /**
   * 处理响应：解析工具调用并通知 UI 层
   */
  async function processResponse(response) {
    try {
      const data = await response.json();
      const choices = data.choices || [];
      for (const choice of choices) {
        const content = choice.message?.content || '';
        if (!content) continue;

        window.postMessage(
          {
            type: '__DEEPSEEK_ENHANCED_RESPONSE__',
            content,
            choiceIndex: choice.index,
          },
          '*'
        );
      }
    } catch (e) {
      // 忽略 JSON 解析错误
    }
  }

  console.log('[DeepSeek Enhanced] Fetch interceptor injected');
})();

